$(document).ready(function(){$(".hidden-box-trigger").on("click",function(e){e.preventDefault(),$(".box--mobile-hidden").slideDown("box--mobile-hidden")}),$(".hidden-team-member-trigger").on("click",function(e){e.preventDefault(),$(".team-member--mobile-hidden").slideDown("team-member--mobile-hidden")}),$(function(){var e=$(".navbar--secondary"),n=$(".hero"),o=$(".main").offset().top;$(window).scroll(function(){var i=$(window).scrollTop();i>=o&&i?(e.addClass("scaleUp"),n.addClass("scaleDown")):(e.removeClass("scaleUp"),n.removeClass("scaleDown"))})})});